/* Select the best network from scan results */
static int zigbee_select_best_network(zigbee_network_descriptor_t *best)
{
    if (best == NULL) {
        return -1;
    }

    if (g_scan_results.count == 0) {
        zigbee_log("ERROR", "No networks found during scan");
        return -1;
    }

    int best_idx = -1;
    uint8_t best_lqi = 0;

    for (uint8_t i = 0; i < g_scan_results.count && i < ZIGBEE_MAX_DEVICES; i++) {
        zigbee_network_descriptor_t *net = &g_scan_results.networks[i];

        if (!net->valid) {
            continue;
        }

        /* Only consider networks that permit joining */
        if (!net->permit_joining) {
            zigbee_log("INFO", "Skipping PAN 0x%04X - not permitting joins", net->pan_id);
            continue;
        }

        /* Must be Zigbee Pro stack profile */
        if (net->stack_profile != 2) {
            zigbee_log("INFO", "Skipping PAN 0x%04X - wrong stack profile %u",
                       net->pan_id, net->stack_profile);
            continue;
        }

        /* Validate channel range */
        if (net->channel < ZIGBEE_MIN_CHANNEL || net->channel > ZIGBEE_MAX_CHANNEL) {
            zigbee_log("WARN", "Skipping PAN 0x%04X - invalid channel %u",
                       net->pan_id, net->channel);
            continue;
        }

        /* Validate PAN ID */
        if (net->pan_id > ZIGBEE_PAN_ID_MAX) {
            zigbee_log("WARN", "Skipping PAN 0x%04X - invalid PAN ID", net->pan_id);
            continue;
        }

        /* Select network with best link quality */
        if (net->lqi > best_lqi) {
            best_lqi = net->lqi;
            best_idx = (int)i;
        }
    }

    if (best_idx < 0) {
        zigbee_log("ERROR", "No suitable network found for joining");
        return -1;
    }

    memcpy(best, &g_scan_results.networks[best_idx], sizeof(zigbee_network_descriptor_t));
    zigbee_log("INFO", "Selected network: PAN=0x%04X, CH=%u, LQI=%u",
               best->pan_id, best->channel, best->lqi);

    return 0;
}

/* Perform trust center authentication */
static zigbee_join_status_t zigbee_authenticate_with_trust_center(void)
{
    if (!g_device.security.trust_center_link_key_set) {
        zigbee_log("ERROR", "No trust center link key configured");
        return JOIN_STATUS_INVALID_KEY;
    }

    zigbee_log("INFO", "Authenticating with trust center using %s security",
               g_device.security.security_mode == SECURITY_MODE_HIGH ?
               "high (install code)" : "standard");

    g_device.state = DEVICE_STATE_AUTHENTICATING;

    /*
     * In production, this would:
     * 1. Send an APS Transport Key request encrypted with the TC link key
     * 2. Receive the network key encrypted with the TC link key
     * 3. Decrypt and install the network key
     * 4. Send an APS Update Device to confirm
     *
     * Simulating successful authentication here.
     */

    /* Simulate receiving network key from trust center */
    uint8_t received_network_key[ZIGBEE_MAX_NETWORK_KEY_LEN];
    zigbee_hal_get_random_bytes(received_network_key, ZIGBEE_MAX_NETWORK_KEY_LEN);

    /* Validate received network key is not all zeros */
    bool all_zero = true;
    for (int i = 0; i < ZIGBEE_MAX_NETWORK_KEY_LEN; i++) {
        if (received_network_key[i] != 0x00) {
            all_zero = false;
            break;
        }
    }

    if (all_zero) {
        zigbee_log("ERROR", "Received invalid network key from trust center");
        secure_memzero(received_network_key, sizeof(received_network_key));
        return JOIN_STATUS_AUTH_FAILED;
    }

    /* Install the network key */
    memcpy(g_device.security.network_key, received_network_key,
           ZIGBEE_MAX_NETWORK_KEY_LEN);
    g_device.security.network_key_set = true;
    g_device.security.key_sequence_number = 0;

    /* Clear temporary key material */
    secure_memzero(received_network_key, sizeof(received_network_key));

    /*
     * After receiving the network key via the TC link key, we should
     * request a unique TC link key for ongoing communication (Zigbee 3.0).
     * This replaces the well-known key with a device-specific one.
     */
    if (g_device.security.security_mode == SECURITY_MODE_STANDARD) {
        zigbee_log("INFO", "Requesting unique trust center link key (Zigbee 3.0)");

        uint8_t unique_tc_key[ZIGBEE_MAX_LINK_KEY_LEN];
        zigbee_hal_get_random_bytes(unique_tc_key, ZIGBEE_MAX_LINK_KEY_LEN);

        /* In production, this key would be negotiated via CBKE or
         * received from the TC encrypted with the current link key */
        memcpy(g_device.security.trust_center_link_key, unique_tc_key,
               ZIGBEE_MAX_LINK_KEY_LEN);

        secure_memzero(unique_tc_key, sizeof(unique_tc_key));
        zigbee_log("INFO", "Unique trust center link key installed");
    }

    zigbee_log("INFO", "Trust center authentication successful");
    return JOIN_STATUS_SUCCESS;
}

/* Join a Zigbee network */
int zigbee_join_network(void)
{
    if (!g_initialized) {
        zigbee_log("ERROR", "Device not initialized");
        return -1;
    }

    if (!g_device.security.trust_center_link_key_set) {
        zigbee_log("ERROR", "Trust center link key not configured. "
                   "Call zigbee_set_trust_center_link_key() first");
        return -1;
    }

    if (g_device.state == DEVICE_STATE_OPERATIONAL ||
        g_device.state == DEVICE_STATE_COMMISSIONED) {
        zigbee_log("WARN", "Device is already joined to a network");
        return -1;
    }

    /* Scan for networks if not already done */
    if (g_scan_results.count == 0) {
        int scan_count = zigbee_scan_networks();
        if (scan_count <= 0) {
            zigbee_log("ERROR", "No networks found");
            g_device.state = DEVICE_STATE_ERROR;
            return -1;
        }
    }

    /* Select best network */
    zigbee_network_descriptor_t target_network;
    secure_memzero(&target_network, sizeof(target_network));

    if (zigbee_select_best_network(&target_network) != 0) {
        g_device.state = DEVICE_STATE_ERROR;
        return -1;
    }

    /* Attempt to join with retries */
    zigbee_join_status_t join_status = JOIN_STATUS_INTERNAL_ERROR;

    for (g_device.join_retries = 0;
         g_device.join_retries < g_device.max_retries;
         g_device.join_retries++) {

        zigbee_log("INFO", "Join attempt %u/%u to PAN 0x%04X on channel %u",
                   g_device.join_retries + 1, g_device.max_retries,
                   target_network.pan_id, target_network.channel);

        g_device.state = DEVICE_STATE_JOINING;

        /* Set radio to target channel */
        if (zigbee_hal_set_channel(target_network.channel) != 0) {
            zigbee_log("ERROR", "Failed to set channel %u", target_network.channel);
            continue;
        }

        /* Send MAC association request */
        if (zigbee_hal_send_association_request(target_network.pan_id,
                                                 target_network.channel) != 0) {
            zigbee_log("ERROR", "Association request failed");
            continue;
        }

        /*
         * In production, wait for association response with timeout.
         * The response would contain our assigned short address.
         */
        g_device.short_address = 0x0001; /* Simulated assigned address */
        g_device.pan_id = target_network.pan_id;
        g_device.channel = target_network.channel;
        memcpy(g_device.extended_pan_id, target_network.extended_pan_id,
               ZIGBEE_EUI64_LEN);

        zigbee_log("INFO", "MAC association successful, short address: 0x%04X",
                   g_device.short_address);

        /* Authenticate with trust center */
        join_status = zigbee_authenticate_with_trust_center();

        if (join_status == JOIN_STATUS_SUCCESS) {
            g_device.state = DEVICE_STATE_JOINED;
            zigbee_log("INFO", "Successfully joined network PAN 0x%04X",
                       g_device.pan_id);
            break;
        }

        zigbee_log("WARN", "Authentication failed with status %d, retrying...",
                   join_status);

        /* Brief delay before retry (in production, use proper timer) */
    }

    if (join_status != JOIN_STATUS_SUCCESS) {
        zigbee_log("ERROR", "Failed to join network after %u attempts",
                   g_device.max_retries);
        g_device.state = DEVICE_STATE_ERROR;

        /* Clear any partial security state */
        secure_memzero(g_device.security.network_key,
                       sizeof(g_device.security.network_key));
        g_device.security.network_key_set = false;

        return -1;
    }

    return 0;
}

/* Commission the device after joining */
int zigbee_commission_device(void)
{
    if (!g_initialized) {
        zigbee_log("ERROR", "Device not initialized");
        return -1;
    }

    if (g_device.state != DEVICE_STATE_JOINED) {
        zigbee_log("ERROR", "Device must be joined before commissioning (state=%d)",
                   g_device.state);
        return -1;
    }

    zigbee_log("INFO", "Starting device commissioning...");

    /*
     * Register endpoints and clusters for the smart light bulb.
     * In production, this sends ZDO Simple Descriptor and Active Endpoint
     * responses to the coordinator/trust center.
     */

    /* Register On/Off cluster */
    zigbee_log("INFO", "Registering endpoint %u, profile 0x%04X",
               g_device.endpoint, g_device.profile_id);
    zigbee_log("INFO", "  Cluster: On/Off (0x%04X)", ZIGBEE_CLUSTER_ON_OFF);
    zigbee_log("INFO", "  Cluster: Level Control (0x%04X)", ZIGBEE_CLUSTER_LEVEL_CONTROL);
    zigbee_log("INFO", "  Cluster: Color Control (0x%04X)", ZIGBEE_CLUSTER_COLOR_CONTROL);

    /*
     * Send Device Announce (ZDO) to notify the network of our presence.
     * This allows the coordinator and other devices to discover us.
     */
    uint8_t device_announce[12];
    secure_memzero(device_announce, sizeof(device_announce));

    /* Sequence number */
    device_announce[0] = 0x01;
    /* Short address (little-endian) */
    device_announce[1] = (uint8_t)(g_device.short_address & 0xFF);
    device_announce[2] = (uint8_t)((g_device.short_address >> 8) & 0xFF);
    /* EUI64 */
    memcpy(&device_announce[3], g_device.eui64, ZIGBEE_EUI64_LEN);
    /* Capability: mains powered, rx on when idle */
    device_announce[11] = 0x8C;

    if (zigbee_hal_send_data(device_announce, sizeof(device_announce)) != 0) {
        zigbee_log("ERROR", "Failed to send device announce");
        return -1;
    }

    g_device.state = DEVICE_STATE_COMMISSIONED;
    zigbee_log("INFO", "Device commissioning complete");

    /* Transition to operational state */
    g_device.state = DEVICE_STATE_OPERATIONAL;
    zigbee_log("INFO", "Smart light bulb is now operational");
    zigbee_log("INFO", "  PAN ID: 0x%04X", g_device.pan_id);
    zigbee_log("INFO", "  Channel: %u", g_device.channel);
    zigbee_log("INFO", "  Short Address: 0x%04X", g_device.short_address);

    return 0;
}

/* Enable permit join mode for adding new devices */
int zigbee_enable_permit_join(uint8_t timeout_seconds)
{
    if (!g_initialized) {
        zigbee_log("ERROR", "Device not initialized");
        return -1;
    }

    if (g_device.state != DEVICE_STATE_OPERATIONAL &&
        g_device.state != DEVICE_STATE_COMMISSIONED) {
        zigbee_log("ERROR", "Device must be operational to enable permit join");
        return -1;
    }

    /* Enforce maximum timeout per Zigbee specification */
    if (timeout_seconds > ZIGBEE_PERMIT_JOIN_TIMEOUT_MAX) {
        zigbee_log("WARN", "Clamping permit join timeout from %u to %u seconds",
                   timeout_seconds, ZIGBEE_PERMIT_JOIN_TIMEOUT_MAX);
        timeout_seconds = ZIGBEE_PERMIT_JOIN_TIMEOUT_MAX;
    }

    if (timeout_seconds == 0) {
        zigbee_log("INFO", "Disabling permit join");
        g_device.permit_join.enabled = false;
        g_device.permit_join.timeout_seconds = 0;
        return 0;
    }

    g_device.permit_join.enabled = true;
    g_device.permit_join.timeout_seconds = timeout_seconds;
    g_device.permit_join.start_time = time(NULL);
    g_device.permit_join.trust_center_only = true;

    /*
     * Send Mgmt_Permit_Joining_req (ZDO cluster 0x0036) to the network.
     * This notifies the coordinator to open the network for new devices.
     */
    uint8_t permit_join_req[3];
    permit_join_req[0] = 0x01; /* Sequence number */
    permit_join_req[1] = timeout_seconds;
    permit_join_req[2] = 0x01; /* TC significance: only TC can authorize */

    if (zigbee_hal_send_data(permit_join_req, sizeof(permit_join_req)) != 0) {
        zigbee_log("ERROR", "Failed to send permit join request");
        g_device.permit_join.enabled = false;
        return -1;
    }

    zigbee_log("INFO", "Permit join enabled for %u seconds (TC-only authorization)",
               timeout_seconds);

    return 0;
}

/* Disable permit join mode */
int zigbee_disable_permit_join(void)
{
    return zigbee_enable_permit_join(0);
}

/* Check if permit join has timed out */
bool zigbee_permit_join_active(void)
{
    if (!g_device.permit_join.enabled) {
        return false;
    }

    time_t now = time(NULL);
    time_t elapsed = now - g_device.permit_join.start_time;

    if (elapsed < 0 || (uint8_t)elapsed >= g_device.permit_join.timeout_seconds) {
        g_device.permit_join.enabled = false;
        g_device.permit_join.timeout_seconds = 0;
        zigbee_log("INFO", "Permit join period has expired");
        return false;
    }

    return true;
}

/* Get remaining permit join time */
uint8_t zigbee_permit_join_remaining(void)
{
    if (!zigbee_permit_join_active()) {
        return 0;
    }

    time_t now = time(NULL);
    time_t elapsed = now - g_device.permit_join.start_time;

    if (elapsed < 0) {
        return 0;
    }

    if ((uint8_t)elapsed >= g_device.permit_join.timeout_seconds) {
        return 0;
    }

    return g_device.permit_join.timeout_seconds - (uint8_t)elapsed;
}

/* Factory reset the device */
int zigbee_factory_reset(void)
{
    if (!g_initialized) {
        zigbee_log("ERROR", "Device not initialized");
        return -1;
    }

    zigbee_log("WARN", "Performing factory reset...");

    /* If joined, send a leave request first */
    if (g_device.state == DEVICE_STATE_OPERATIONAL ||
        g_device.state == DEVICE_STATE_COMMISSIONED ||
        g_device.state == DEVICE_STATE_JOINED) {

        zigbee_log("INFO", "Sending network leave request");
        g_device.state = DEVICE_STATE_LEAVE;

        /* Send ZDO Mgmt_Leave_req */
        uint8_t leave_req[10];
        secure_memzero(leave_req, sizeof(leave_req));
        leave_req[0] = 0x01; /* Sequence */
        memcpy(&leave_req[1], g_device.eui64, ZIGBEE_EUI64_LEN);
        leave_req[9] = 0x00; /* No rejoin, no remove children */

        zigbee_hal_send_data(leave_req, sizeof(leave_req));
    }

    /* Securely clear all security material */
    secure_memzero(g_device.security.trust_center_link_key,
                   sizeof(g_device.security.trust_center_link_key));
    secure_memzero(g_device.security.network_key,
                   sizeof(g_device.security.network_key));
    g_device.security.trust_center_link_key_set = false;
    g_device.security.network_key_set = false;
    g_device.security.key_sequence_number = 0;

    /* Clear network parameters */
    g_device.short_address = 0xFFFE;
    g_device.pan_id = 0xFFFF;
    g_device.channel = 0;
    secure_memzero(g_device.extended_pan_id, sizeof(g_device.extended_pan_id));

    /* Disable permit join */
    g_device.permit_join.enabled = false;
    g_device.permit_join.timeout_seconds = 0;

    /* Clear scan results */
    secure_memzero(&g_scan_results, sizeof(g_scan_results));

    /* Reset state */
    g_device.state = DEVICE_STATE_INITIALIZED;
    g_device.join_retries = 0;

    zigbee_log("INFO", "Factory reset complete. Device ready for re-commissioning");

    return 0;
}

/* Get current device state */
zigbee_device_state_t zigbee_get_device_state(void)
{
    return g_device.state;
}

/* Get device short address */
uint16_t zigbee_get_short_address(void)
{
    return g_device.short_address;
}

/* Cleanup and shutdown */
int zigbee_device_shutdown(void)
{
    if (!g_initialized) {
        return 0;
    }

    zigbee_log("INFO", "Shutting down Zigbee device...");

    /* Disable permit join */
    if (g_device.permit_join.enabled) {
        zigbee_disable_permit_join();
    }

    /* Securely clear all sensitive data */
    secure_memzero(&g_device.security, sizeof(g_device.security));
    secure_memzero(&g_scan_results, sizeof(g_scan_results));
    secure_memzero(&g_device, sizeof(g_device));

    g_initialized = false;

    zigbee_log("INFO", "Zigbee device shutdown complete");
    return 0;
}

/* Periodic tick handler - call from main loop */
void zigbee_tick(void)
{
    if (!g_initialized) {
        return;
    }

    /* Check permit join timeout */
    if (g_device.permit_join.enabled) {
        if (!zigbee_permit_join_active()) {
            zigbee_log("INFO", "Permit join auto-disabled after timeout");
        }
    }

    /*
     * In production, this would also handle:
     * - Network key rotation
     * - Link status monitoring
     * - Rejoin if connection lost
     * - Periodic keep-alive messages
     */
}

/* Consumer-friendly setup flow */
int zigbee_easy_setup(void)
{
    zigbee_log("INFO", "=== Smart Light Bulb Easy Setup ===");

    /* Step 1: Set default trust center link key for initial joining */
    zigbee_log("INFO", "Step 1: Configuring security credentials...");
    if (zigbee_set_default_trust_center_link_key() != 0) {
        zigbee_log("ERROR", "Failed to set trust center link key");
        return -1;
    }

    /* Step 2: Scan and join network */
    zigbee_log("INFO", "Step 2: Searching for Zigbee network...");
    if (zigbee_join_network() != 0) {
        zigbee_log("ERROR", "Failed to join network. Please ensure your Zigbee "
                   "coordinator is powered on and in pairing mode.");
        return -1;
    }

    /* Step 3: Commission the device */
    zigbee_log("INFO", "Step 3: Registering light bulb on network...");
    if (zigbee_commission_device() != 0) {
        zigbee_log("ERROR", "Failed to commission device");
        zigbee_factory_reset();
        return -1;
    }

    /* Step 4: Enable permit join briefly for setup convenience */
    zigbee_log("INFO", "Step 4: Enabling discovery mode...");
    if (zigbee_enable_permit_join(ZIGBEE_PERMIT_JOIN_TIMEOUT_DEFAULT) != 0) {
        zigbee_log("WARN", "Failed to enable permit join (non-critical)");
    }

    zigbee_log("INFO", "=== Setup Complete! ===");
    zigbee_log("INFO", "Your smart light bulb is ready to use.");
    zigbee_log("INFO", "Discovery mode active for %u seconds for additional devices.",
               ZIGBEE_PERMIT_JOIN_TIMEOUT_DEFAULT);

    return 0;
}

/* Main entry point */
int main(void)
{
    /* Seed PRNG (in production, use hardware TRNG) */
    srand((unsigned int)time(NULL));

    /* Device EUI64 - in production, read from hardware/OTP */
    uint8_t device_eui64[ZIGBEE_EUI64_LEN] = {
        0x00, 0x11, 0x22, 0x33, 0x44, 0x55, 0x66, 0x77
    };

    zigbee_log("INFO", "Smart Light Bulb Firmware v1.0.0");
    zigbee_log("INFO", "Zigbee 3.0 Compliant");

    /* Initialize device */
    if (zigbee_device_init(device_eui64) != 0) {
        zigbee_log("ERROR", "Device initialization failed");
        return EXIT_FAILURE;
    }

    /* Run consumer-friendly setup */
    if (zigbee_easy_setup() != 0) {
        zigbee_log("ERROR", "Easy setup failed. Please power cycle the bulb to retry.");
        zigbee_device_shutdown();
        return EXIT_FAILURE;
    }

    /* Main operational loop */
    zigbee_log("INFO", "Entering main operational loop...");

    int loop_count = 0;
    while (loop_count < 10) { /* Limited iterations for demonstration */
        zigbee_tick();

        /* Check device state */
        if (g_device.state == DEVICE_STATE_ERROR) {
            zigbee_log("ERROR", "Device entered error state, attempting recovery");
            zigbee_factory_reset();
            if (zigbee_easy_setup() != 0) {
                zigbee_log("ERROR", "Recovery failed");
                break;
            }
        }

        /* Report permit join status */
        if (zigbee_permit_join_active()) {
            uint8_t remaining = zigbee_permit_join_remaining();
            if (remaining > 0 && remaining % 60 == 0) {
                zigbee_log("INFO", "Permit join: %u seconds remaining", remaining);
            }
        }

        loop_count++;
    }

    /* Cleanup */
    zigbee_log("INFO", "Shutting down...");
    zigbee_device_shutdown();

    return EXIT_SUCCESS;
}